final:
module RefModule (
  input clk,
  input reset,
  input [31:0] data_in,
  output [31:0] data_out
);

  reg [31:0] data_reg;

  always @(posedge clk) begin
    if (reset) begin
      data_reg <= 0;
    end else begin
      data_reg <= data_in;
    end
  end

  wire __data_out_tmp = data_reg;
  assign data_out = __data_out_tmp;

endmodule
